import { create } from 'zustand'

const useProgressBarStore = create((set) => ({
    progressBars: [],
    addProgressBar: (pb) => set((state) => ({
        progressBars: [...state.progressBars, {
            ...pb,
            active: state.progressBars.length === 0
        }]
    })),
    completeProgressBar: (id) => set((state) => {
        const completedIdx = state.progressBars.find(pb => pb.id === id)?.idx
        return {
            progressBars: state.progressBars.map(pb => {
                if (pb.id === id) return { ...pb, completed: true, active: false }
                if (pb.idx === completedIdx + 1) return { ...pb, active: true }
                return pb
            })
        }
    })
}))

export default useProgressBarStore
